import { useState } from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Dashboard from './Pages/Dashboard';
import StudySession from './Pages/StudySession';

function App() {
  // Lift the schedule state here so it persists acrosAs navigation
  const [schedule, setSchedule] = useState(null);

  // Function to mark a specific day as done
  const markDayComplete = (dayId) => {
    setSchedule(prevSchedule => 
      prevSchedule.map(item => 
        item.day === parseInt(dayId) ? { ...item, status: 'completed' } : item
      )
    );
  };

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/dashboard" element={<Dashboard schedule={schedule} setSchedule={setSchedule} />} />
        <Route path="/study-session/:day" element={<StudySession markDayComplete={markDayComplete} />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App
